import React from "react";
import type { IKitsInputMask } from "@lmb/kitsconcerto-types";
import KitsContainer from "../../Helpers/FormContainer";
import { formatWithMask } from "../../Helpers/native/mask";
import { Input, InputField } from "@lmb/kitsconcertomobile";
import Addons from "../../Helpers/Addons";
import { useFormInputController } from "../../Helpers/useFormInputController";

const KitsInputMask = ({ ref, ...props }: IKitsInputMask) => {
    const {
        id,
        label,
        required,
        value,
        defaultValue,
        attached,
        errors,
        hideError,
        invalid,
        isFloatedLabel,
        disabled,
        helperText,
        mask,
        unmask,
        leftAddon,
        rightAddon,
        onChange,
        placeholder,
    } = props;

    const { value: displayValue, emitChange } =
        useFormInputController<string>({
            value,
            defaultValue,
            onChange,
        });

    const handleChangeText = (raw: string) => {
        let masked = raw;
        let unmaskedValue = raw;

        if (mask) {
            const res = formatWithMask(raw, mask);
            masked = res.masked;
            unmaskedValue = res.unmasked;
        }

        emitChange(unmask ? unmaskedValue : masked);
    };

    if(attached){
        return(
            <Input
                variant="outline"
                size="md"
                isDisabled={disabled}
                isInvalid={!!invalid}
                style={{ width: "100%" }}
            >
                <Addons leftAddon={leftAddon} rightAddon={rightAddon}>
                    <InputField
                        ref={ref}
                        value={displayValue ?? ""}
                        placeholder={placeholder}
                        onChangeText={handleChangeText}
                    />
                </Addons>
            </Input>
        )
    }
    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={required}
            disabled={disabled}
        >
            <Input
                variant="outline"
                size="md"
                isDisabled={disabled}
                isInvalid={!!invalid}
                style={{ width: "100%" }}
            >
                <Addons leftAddon={leftAddon} rightAddon={rightAddon}>
                    <InputField
                        ref={ref}
                        value={displayValue ?? ""}
                        placeholder={placeholder}
                        onChangeText={handleChangeText}
                    />
                </Addons>
            </Input>
        </KitsContainer>
    );
};

export default KitsInputMask;
